                            className="absolute -bottom-4 left-1/2 -translate-x-1/2 bg-slate-900 dark:bg-white text-white dark:text-slate-900 px-6 py-2 rounded-full text-xs font-bold uppercase tracking-widest shadow-xl flex items-center gap-2 hover:bg-brand-600 dark:hover:bg-brand-400 hover:text-white transition-all hover:scale-105"
                        >
                            <Download size={14} /> Download QR
                        </a>
                    </>
                  ) : (
                    <div className="w-56 h-56 bg-slate-50 dark:bg-slate-800 animate-pulse rounded-xl flex items-center justify-center">
                      <Loader2 className="animate-spin text-brand-500" size={32} />
                    </div>
                  )}
                </div>
             </div>
             <p className="mt-8 text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-[0.25em] hc-text flex items-center gap-2">
                <QrCode size={14} /> Scan for Verification
             </p>
          </div>

          <div className="bg-slate-50 dark:bg-slate-800/50 rounded-2xl p-6 mb-8 border border-slate-100 dark:border-slate-800/50 hc-border">
             <div className="flex items-center justify-center text-slate-500 dark:text-slate-400 text-sm font-medium mb-1">
                <ShieldCheck size={16} className="mr-2 text-brand-500" /> 
                <span className="uppercase tracking-widest text-[10px] font-bold">Transaction Hash</span>
             </div>
             <code className="font-mono text-xs text-slate-700 dark:text-slate-300 bg-white dark:bg-slate-900 px-3 py-1 rounded border border-slate-200 dark:border-slate-700">
                {Math.random().toString(36).substring(2, 6).toUpperCase()}-{Math.random().toString(36).substring(2, 6).toUpperCase()}-{Math.random().toString(36).substring(2, 6).toUpperCase()}
             </code>
          </div>

          <button 
            onClick={() => window.location.reload()}
            className="w-full sm:w-auto px-10 py-4 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-xl hover:bg-brand-600 dark:hover:bg-brand-400 dark:hover:text-white transition-all font-bold shadow-xl shadow-slate-900/10 hc-border hc-button-primary"
          >
            Start New Application
          </button>
        </div>
      </Layout>
    );
  }

  return (
    <Layout theme={theme} setTheme={setTheme} onAdminClick={() => setView('admin')}>
      {/* Toast Container */}
      <div className="fixed top-20 right-4 z-[9999] flex flex-col items-end pointer-events-none w-full max-w-sm px-4">
        {toasts.map(toast => (
          <div key={toast.id} className="pointer-events-auto">
            <Toast toast={toast} onClose={removeToast} />
          </div>
        ))}
      </div>

      <div className="max-w-4xl mx-auto">
        <StepIndicator currentStep={currentStep} totalSteps={STEPS.length} steps={STEPS} />

        <div className="mt-8 mb-12 min-h-[500px]">
          {currentStep === 1 && <Step1Scholar data={formData} updateData={updateFormData} />}
          {currentStep === 2 && <Step2Program data={formData} updateData={updateFormData} />}
          {currentStep === 3 && <Step3GuarantorWitness data={formData} updateData={updateFormData} />}
          {currentStep === 4 && (
            <div className="space-y-8 animate-in fade-in slide-up">
              <Step4Review data={formData} updateData={updateFormData} />

              <div className="bg-gradient-to-br from-brand-50/50 via-slate-50 to-indigo-50/50 dark:from-slate-800/50 dark:via-slate-800 dark:to-indigo-950/20 p-8 rounded-3xl border border-brand-100/50 dark:border-brand-900/30 shadow-glass hc-bg hc-border overflow-hidden relative">
                {isReviewing && (
                  <div className="absolute inset-0 bg-white/60 dark:bg-slate-900/60 backdrop-blur-sm z-10 flex flex-col items-center justify-center animate-in fade-in">
                    <BrainCircuit size={48} className="text-brand-500 animate-pulse mb-4" />
                    <p className="text-sm font-bold text-slate-700 dark:text-slate-300">Gemini is analyzing your application...</p>
                  </div>
                )}

                <div className="flex items-center justify-between mb-6">
                  <div className="flex items-center text-brand-800 dark:text-brand-200 font-black text-lg hc-text uppercase tracking-tighter">
                    <Sparkles className="mr-3 text-brand-500" size={24} /> AI Expert Review
                  </div>
                  {!aiReview && !isReviewing && (
                    <button 
                      onClick={handleAiReview}
                      className="px-5 py-2.5 bg-brand-600 text-white rounded-xl shadow-lg hover:bg-brand-700 transition-all flex items-center text-sm font-bold"
                    >
                      Audit My Form
                    </button>
                  )}
                </div>

                {aiReview ? (
                  <div className="space-y-4 animate-in fade-in slide-in-from-top-2">
                    <div className="flex items-center justify-between mb-2">
                      <span className="text-sm font-bold text-slate-500 dark:text-slate-400 hc-text uppercase tracking-widest">Readiness Score</span>
                      <span className={`text-xl font-black ${aiReview.score >= 80 ? 'text-success-600' : 'text-warning-600'}`}>{aiReview.score}%</span>
                    </div>
                    <div className="w-full bg-slate-200 dark:bg-slate-700 h-3 rounded-full overflow-hidden">
                      <div className="h-full bg-brand-500 transition-all duration-1000 ease-out shadow-glow" style={{ width: `${aiReview.score}%` }}></div>
                    </div>
                    <div className="p-5 bg-white/50 dark:bg-slate-900/50 rounded-2xl border border-white/50 dark:border-slate-700/50">
                      <p className="text-slate-700 dark:text-slate-200 italic leading-relaxed hc-text">"{aiReview.feedback}"</p>
                    </div>
                    <button onClick={() => setAiReview(null)} className="text-[10px] text-slate-400 hover:text-brand-500 font-black uppercase tracking-[0.2em] transition-colors">Re-evaluate Application</button>
                  </div>
                ) : (
                  <p className="text-slate-500 dark:text-slate-400 hc-text leading-relaxed">
                    Our embedded AI will check for professional consistency, program eligibility markers, and common data entry errors before final execution.
                  </p>
                )}
              </div>
            </div>
          )}
        </div>

        <nav className="flex items-center justify-between pt-10 border-t border-slate-200 dark:border-slate-800">
          <button
            onClick={prevStep}
            disabled={currentStep === 1 || isSubmitting}
            className={`flex items-center px-8 py-4 rounded-2xl font-bold transition-all text-sm
              ${currentStep === 1 
                ? 'text-slate-300 dark:text-slate-700 cursor-not-allowed' 
                : 'text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800 hover:translate-x-[-4px]'
              }`}
          >
            <ArrowLeft size={18} className="mr-3" /> Back
          </button>

          {currentStep === STEPS.length ? (
            <button
              onClick={handleSubmit}
              disabled={isSubmitting || !formData.signatures.agreedToTerms}
              className="flex items-center px-12 py-5 bg-slate-950 dark:bg-brand-600 text-white rounded-2xl hover:bg-slate-900 dark:hover:bg-brand-500 transition-all shadow-2xl shadow-brand-500/20 disabled:opacity-50 disabled:shadow-none hc-border font-black text-lg group"
            >
              {isSubmitting ? (
                <>
                  <Loader2 size={22} className="mr-3 animate-spin" /> Transmitting...
                </>
              ) : (
                <>
                  Execute Bond <Send size={20} className="ml-4 group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform" />
                </>
              )}
            </button>
          ) : (
            <button
              onClick={nextStep}
              className="flex items-center px-12 py-5 bg-brand-600 text-white rounded-2xl hover:bg-brand-700 transition-all shadow-xl shadow-brand-500/30 hc-border font-black text-lg group"
            >
              Next Step <ArrowRight size={20} className="ml-4 group-hover:translate-x-1 transition-transform" />
            </button>
          )}
        </nav>
      </div>
    </Layout>
  );
};

export default App;

