import React, { ReactNode, useState, useEffect } from 'react';
import { ThemeSwitcher, Theme } from './ui/ThemeSwitcher';
import { Tooltip } from './ui/Tooltip';
import { Download, Share2, ShieldCheck, Cpu } from 'lucide-react';

interface Props {
  children: ReactNode;
  theme: Theme;
  setTheme: (theme: Theme) => void;
  onAdminClick: () => void;
}

export const Layout: React.FC<Props> = ({ children, theme, setTheme, onAdminClick }) => {
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [isInstallable, setIsInstallable] = useState(false);
  const [canShare, setCanShare] = useState(false);

  useEffect(() => {
    if (navigator.share) {
      setCanShare(true);
    }

    const handler = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
      setIsInstallable(true);
    };

    window.addEventListener('beforeinstallprompt', handler);

    if (window.matchMedia('(display-mode: standalone)').matches) {
      setIsInstallable(false);
    }

    return () => {
      window.removeEventListener('beforeinstallprompt', handler);
    };
  }, []);

  const handleInstallClick = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    if (outcome === 'accepted') {
      setIsInstallable(false);
    }
    setDeferredPrompt(null);
  };

  const handleShare = async () => {
    try {
      await navigator.share({
        title: 'Sentinel Portal',
        text: 'Digital agreement portal for the Techbridge University College scholarship scheme.',
        url: window.location.href,
      });
    } catch (err) {
      console.log('Share failed:', err);
    }
  };

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-500 ${theme === 'high-contrast' ? 'high-contrast' : ''}`}>
      {/* Decorative Background Glows */}
      {theme !== 'high-contrast' && (
        <div className="fixed inset-0 z-[-1] overflow-hidden pointer-events-none">
          <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-600/10 rounded-full blur-[120px] animate-pulse-slow"></div>
          <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-600/10 rounded-full blur-[120px] animate-pulse-slow" style={{ animationDelay: '1.5s' }}></div>
        </div>
      )}

      {/* Glass Header */}
      <header className="sticky top-0 z-50 glass-panel border-b-0 rounded-none sm:rounded-b-2xl sm:mx-4 sm:mt-2 transition-all">
        <div className="max-w-7xl mx-auto px-6 py-4 flex items-center justify-between">
          {/* Brand */}
          <div className="flex items-center space-x-4">
            <div className="relative group">
               <div className="absolute -inset-1 bg-gradient-to-r from-blue-500 to-purple-600 rounded-lg blur opacity-25 group-hover:opacity-75 transition duration-500"></div>
               <div className="relative h-12 w-12 bg-slate-900 rounded-lg flex items-center justify-center border border-slate-700">
                  <Cpu className="text-blue-400" size={24} />
               </div>
            </div>
            <div className="hidden md:block">
                <h1 className="text-xl font-bold tracking-tight text-white">
                  SENTINEL <span className="font-light text-slate-400">AGENT</span>
                </h1>
                <p className="text-[10px] text-blue-400 font-mono tracking-widest uppercase">Scholarship Command Center</p>
            </div>
          </div>

          {/* Hero/Title - Hidden on mobile to save space */}
          <div className="hidden lg:flex flex-col items-center justify-center flex-1 mx-4 text-center">
             <span className="px-3 py-1 rounded-full bg-slate-800/50 border border-slate-700 text-[10px] text-slate-300 font-mono mb-1">
               SECURE CONNECTION ESTABLISHED
             </span>
          </div>

          {/* Actions */}
          <div className="flex items-center space-x-3">
             {canShare && (
               <Tooltip content="Share Uplink">
                 <button 
                   onClick={handleShare}
                   className="p-2 text-slate-400 hover:text-blue-400 transition-colors"
                 >
                   <Share2 size={20} />
                 </button>
               </Tooltip>
             )}
             {isInstallable && (
               <Tooltip content="Install Terminal">
                 <button 
                   onClick={handleInstallClick}
                   className="flex items-center px-4 py-2 bg-blue-600/20 text-blue-400 border border-blue-500/30 rounded-lg text-xs font-bold hover:bg-blue-600/30 transition-all uppercase tracking-wider"
                 >
                   <Download size={14} className="mr-2" /> 
                   Install
                 </button>
               </Tooltip>
             )}
             <div className="h-6 w-px bg-slate-700 mx-2"></div>
             <ThemeSwitcher currentTheme={theme} setTheme={setTheme} />
          </div>
        </div>
      </header>

      <main className="flex-grow container max-w-6xl mx-auto px-4 py-8 sm:py-12 relative z-10">
        {children}
      </main>

      {/* Glass Footer */}
      <footer className="mt-auto glass-panel border-t-0 rounded-none sm:rounded-t-2xl sm:mx-4 sm:mb-2 py-8">
        <div className="max-w-6xl mx-auto px-6 flex flex-col md:flex-row justify-between items-center text-slate-400 text-sm">
          <div className="flex flex-col items-center md:items-start space-y-2">
             <div className="flex items-center space-x-2">
                <div className="h-2 w-2 rounded-full bg-green-500 animate-pulse"></div>
                <span className="font-mono text-xs text-green-500">SYSTEM OPERATIONAL</span>
             </div>
             <p className="text-slate-500 text-xs">Techbridge University College • Oyibi Campus</p>
