          <div className="mt-6 md:mt-0 flex flex-col items-center md:items-end space-y-3">
            <Tooltip content="Level 4 Clearance Required">
              <button 
                onClick={onAdminClick}
                className="flex items-center px-4 py-2 rounded-lg bg-slate-800 hover:bg-slate-700 border border-slate-700 transition-all text-xs font-mono text-slate-300 group"
