import React, { useId } from 'react';
import { IMaskInput } from 'react-imask';

interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  label: string;
  error?: string;
  mask?: string;
}

export const Input: React.FC<InputProps> = ({ 
  label, 
  error, 
  className, 
  id, 
  mask,
  onChange,
  value,
  ...props 
}) => {
  const generatedId = useId();
  const inputId = id || generatedId;

  const baseClasses = `w-full px-4 py-3 rounded-lg border transition-all outline-none font-medium
    bg-slate-900/40 text-slate-100 placeholder-slate-500
    focus:bg-slate-900/60 focus:border-blue-500/50 focus:shadow-[0_0_15px_rgba(96,165,250,0.15)] focus:ring-1 focus:ring-blue-500/30
    disabled:opacity-50 disabled:cursor-not-allowed
    ${error 
        ? 'border-red-500/50 bg-red-900/10 focus:border-red-500 focus:shadow-[0_0_15px_rgba(248,113,113,0.15)]' 
        : 'border-slate-700/50 hover:border-slate-600'
    } ${className}`;

  return (
    <div className="w-full group">
      <label 
        htmlFor={inputId} 
        className="block text-xs font-bold text-slate-400 mb-2 uppercase tracking-wide group-focus-within:text-blue-400 transition-colors"
      >
        {label}
      </label>

      {mask ? (
        <IMaskInput
          mask={mask}
          unmask={false}
          id={inputId}
          className={baseClasses}
          value={value as string}
          onAccept={(val, mask) => {
            if (onChange) {
              const event = {
                target: { value: val, name: props.name },
                currentTarget: { value: val, name: props.name }
              } as any;
              onChange(event);
            }
          }}
          aria-invalid={!!error}
          aria-describedby={error ? `${inputId}-error` : undefined}
          {...(props as any)}
        />
      ) : (
        <input
          id={inputId}
          aria-invalid={!!error}
          aria-describedby={error ? `${inputId}-error` : undefined}
          className={baseClasses}
          value={value}
          onChange={onChange}
          {...props}
        />
      )}

      {error && (
        <p 
            id={`${inputId}-error`} 
            role="alert" 
            className="mt-2 text-xs text-red-400 font-medium flex items-center animate-fade-in"
        >
            <span className="w-1.5 h-1.5 rounded-full bg-red-500 mr-2"></span>
            {error}
        </p>
      )}
    </div>
  );
};

import React from 'react';
import { Check } from 'lucide-react';

interface Props {
  currentStep: number;
  totalSteps: number;
  steps: string[];
}

export const StepIndicator: React.FC<Props> = ({ currentStep, totalSteps, steps }) => {
  return (
    <div className="w-full py-8 mb-4" role="progressbar" aria-valuenow={currentStep} aria-valuemin={1} aria-valuemax={totalSteps}>
      <div className="flex items-center justify-between relative max-w-3xl mx-auto px-4">
        {/* Background Line */}
        <div className="absolute left-4 right-4 top-1/2 transform -translate-y-1/2 h-0.5 bg-slate-800 -z-10 rounded-full" />

        {/* Progress Line */}
        <div 
            className="absolute left-4 top-1/2 transform -translate-y-1/2 h-0.5 bg-gradient-to-r from-blue-500 to-purple-500 -z-10 transition-all duration-700 ease-in-out shadow-[0_0_10px_rgba(167,139,250,0.5)]" 
            style={{ width: `calc(${((currentStep - 1) / (totalSteps - 1)) * 100}% - 2rem)` }}
        />

        {steps.map((label, index) => {
            const stepNum = index + 1;
            const isActive = stepNum === currentStep;
            const isCompleted = stepNum < currentStep;

            return (
                <div key={label} className="flex flex-col items-center group relative cursor-default">
                    {/* Step Circle */}
                    <div 
                        className={`w-10 h-10 sm:w-12 sm:h-12 rounded-xl flex items-center justify-center border transition-all duration-500 relative z-10 backdrop-blur-md
                        ${isActive 
                            ? 'border-blue-400 bg-blue-500/20 text-blue-100 shadow-[0_0_20px_rgba(96,165,250,0.4)] scale-110' 
                            : isCompleted 
                                ? 'border-purple-500 bg-purple-500/20 text-purple-200 shadow-[0_0_10px_rgba(168,85,247,0.3)]' 
                                : 'border-slate-700 bg-slate-900/80 text-slate-500'
                        }
                        `}
                    >
                        {isCompleted ? (
                            <Check size={20} strokeWidth={3} className="animate-in fade-in zoom-in duration-300" />
                        ) : (
                            <span className={`font-mono font-bold ${isActive ? 'text-lg' : 'text-base'}`}>{stepNum}</span>
                        )}

                        {/* Active Glow Ring */}
                        {isActive && (
                            <div className="absolute inset-0 rounded-xl animate-ping bg-blue-500/20 -z-10 duration-1000"></div>
                        )}
                    </div>

                    {/* Label */}
                    <div className={`absolute top-full mt-4 flex flex-col items-center w-32 text-center transition-all duration-300 ${isActive ? 'opacity-100 translate-y-0' : 'opacity-40 -translate-y-1'}`}>
                        <span className={`text-[10px] font-bold uppercase tracking-widest mb-1 ${isActive ? 'text-blue-400' : 'text-slate-500'}`}>
                            Step 0{stepNum}
                        </span>
                        <span className={`text-xs font-medium hidden sm:block whitespace-nowrap ${isActive ? 'text-white' : 'text-slate-400'}`}>
                            {label}
                        </span>
                    </div>
                </div>
            )
        })}
      </div>
    </div>
  );
};

import React, { useEffect } from 'react';
import { CheckCircle, AlertTriangle, Info, X, AlertCircle } from 'lucide-react';

export type ToastType = 'success' | 'error' | 'warning' | 'info';

export interface ToastMessage {
  id: string;
  type: ToastType;
  title: string;
  message: string;
}

interface ToastProps {
  toast: ToastMessage;
  onClose: (id: string) => void;
}

export const Toast: React.FC<ToastProps> = ({ toast, onClose }) => {
  useEffect(() => {
    const timer = setTimeout(() => {
      onClose(toast.id);
    }, 6000);
    return () => clearTimeout(timer);
  }, [toast.id, onClose]);

  const config = {
    success: { icon: CheckCircle, color: 'text-green-400', border: 'border-l-green-400', bg: 'bg-green-500/10' },
    error: { icon: AlertCircle, color: 'text-red-400', border: 'border-l-red-400', bg: 'bg-red-500/10' },
    warning: { icon: AlertTriangle, color: 'text-yellow-400', border: 'border-l-yellow-400', bg: 'bg-yellow-500/10' },
    info: { icon: Info, color: 'text-blue-400', border: 'border-l-blue-400', bg: 'bg-blue-500/10' },
  };

  const style = config[toast.type];
  const Icon = style.icon;

  return (
    <div 
      role="alert"
      className={`relative flex items-start p-4 mb-3 max-w-sm w-full rounded-r-lg border-l-4 
      glass-panel shadow-glass animate-slide-in-right overflow-hidden
      ${style.border} ${style.bg}`}
    >
      <div className={`flex-shrink-0 mr-3 mt-0.5 ${style.color}`}>
        <Icon size={20} />
      </div>
      <div className="flex-1 mr-6">
        <h4 className="text-sm font-bold text-slate-100 tracking-wide mb-1">{toast.title}</h4>
        <p className="text-xs text-slate-400 leading-relaxed">{toast.message}</p>
      </div>
      <button 
        onClick={() => onClose(toast.id)}
        className="absolute top-2 right-2 p-1 text-slate-500 hover:text-white transition-colors rounded-full hover:bg-slate-700/50"
        aria-label="Close notification"
      >
        <X size={14} />
      </button>

      {/* Timer Bar */}
      <div className="absolute bottom-0 left-0 h-[2px] bg-gradient-to-r from-transparent via-slate-500/30 to-transparent w-full animate-[pulse_2s_infinite]"></div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Layout } from './components/Layout';
import { StepIndicator } from './components/StepIndicator';
import { Step1Scholar } from './components/steps/Step1Scholar';
import { Step2Program } from './components/steps/Step2Program';
import { Step3GuarantorWitness } from './components/steps/Step3GuarantorWitness';
import { Step4Review } from './components/steps/Step4Review';
import { AdminPanel } from './components/admin/AdminPanel';
import { Theme } from './components/ui/ThemeSwitcher';
import { Toast, ToastMessage, ToastType } from './components/ui/Toast';
import { FormData, INITIAL_DATA } from './types';
import { ArrowRight, ArrowLeft, Loader2, Send, CheckCircle, Sparkles, BrainCircuit, ShieldCheck, QrCode, Download, RefreshCw } from 'lucide-react';
import { submitApplication } from './services/api';
import { logAction } from './services/auditLog';
import { GoogleGenAI } from "@google/genai";
import QRCode from 'qrcode';

const STEPS = [
  "Identity",
  "Academics",
  "Legal",
  "Review"
];

const STORAGE_KEY = 'sentinel_scholarship_form_v2_data';

const App: React.FC = () => {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState<FormData>(() => {
    try {
      const savedData = localStorage.getItem(STORAGE_KEY);
      return savedData ? JSON.parse(savedData) : INITIAL_DATA;
    } catch (e) {
      return INITIAL_DATA;
    }
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [view, setView] = useState<'form' | 'admin'>('form');

  // Sentinel Default: Dark Mode
  const [theme, setTheme] = useState<Theme>(() => {
    const saved = localStorage.getItem('sentinel_theme');
    return (saved as Theme) || 'dark';
  });

  const [toasts, setToasts] = useState<ToastMessage[]>([]);

  // AI Review State
  const [aiReview, setAiReview] = useState<{ feedback: string; score: number } | null>(null);
  const [isReviewing, setIsReviewing] = useState(false);

  // QR Code State
  const [qrCodeUrl, setQrCodeUrl] = useState<string>('');

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(formData));
  }, [formData]);

  useEffect(() => {
    localStorage.setItem('sentinel_theme', theme);
    const root = window.document.documentElement;
    root.classList.remove('dark', 'light', 'high-contrast');

    // Sentinel uses dark mode class for its primary look
    if (theme === 'dark' || theme === 'light') {
      root.classList.add('dark'); // Force dark class for Sentinel styling
    } else if (theme === 'high-contrast') {
      root.classList.add('high-contrast');
    }
  }, [theme]);

  useEffect(() => {
    if (isSuccess) {
      const targetUrl = window.location.href;
      QRCode.toDataURL(targetUrl, {
        width: 300,
        margin: 2,
        color: {
          dark: '#0f172a',
          light: '#ffffff',
        },
        errorCorrectionLevel: 'H'
      })
      .then(url => setQrCodeUrl(url))
      .catch(err => console.error("QR Code Gen Error", err));
