      setAiReview(result);
      addToast('info', 'Audit Complete', `Confidence Score: ${result.score}%`);
    } catch (error) {
      console.error("AI Error:", error);
      setAiReview({ feedback: "AI Review unavailable. Proceed with manual check.", score: 100 });
      addToast('error', 'Connection Failed', "AI Audit unavailable.");
    } finally {
      setIsReviewing(false);
    }
  };

  const handleSubmit = async () => {
    if (!formData.signatures.agreedToTerms) {
      addToast('error', 'Legal Hold', "Terms acceptance mandatory.");
      return;
    }

    setIsSubmitting(true);
    try {
      const result = await submitApplication(formData);
      if (result.success) {
        setIsSuccess(true);
        localStorage.removeItem(STORAGE_KEY);
        addToast('success', 'Transmission Secured', "Bond executed successfully.");
      }
    } catch (error) {
      addToast('error', 'Transmission Failed', "Retry uplink.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (view === 'admin') {
    return (
      <Layout theme={theme} setTheme={setTheme} onAdminClick={() => setView('form')}>
        <AdminPanel onLogout={() => setView('form')} onRunSimulation={() => {}} />
      </Layout>
    );
  }

  if (isSuccess) {
    return (
      <Layout theme={theme} setTheme={setTheme} onAdminClick={() => setView('admin')}>
        <div className="max-w-xl mx-auto mt-8 glass-panel rounded-2xl p-8 md:p-12 text-center animate-scale-in relative overflow-hidden">
          {/* Accent Top Bar */}
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-blue-500 via-purple-500 to-blue-500"></div>

          <div className="w-20 h-20 bg-green-500/10 rounded-full flex items-center justify-center mx-auto mb-6 border border-green-500/20 shadow-[0_0_30px_rgba(74,222,128,0.2)]">
            <CheckCircle size={40} className="text-green-400" strokeWidth={2.5} />
          </div>

          <h2 className="text-3xl font-bold text-white mb-2 tracking-tight">Bond Executed</h2>
          <p className="text-slate-400 mb-8 max-w-sm mx-auto">
            Agreement for <span className="text-slate-200 font-semibold">{formData.scholar.fullName}</span> transmitted to registrar.
          </p>

          {/* QR Section */}
          <div className="bg-slate-900/50 p-6 rounded-xl border border-slate-700/50 mb-8 inline-block">
            {qrCodeUrl ? (
              <div className="space-y-4">
                 <img src={qrCodeUrl} alt="QR Code" className="w-48 h-48 rounded-lg mix-blend-normal opacity-90 mx-auto" />
                 <a 
                     href={qrCodeUrl} 
                     download={`sentinel-qr-${formData.scholar.idNumber}.png`}
                     className="flex items-center justify-center px-4 py-2 bg-slate-800 hover:bg-slate-700 text-blue-400 rounded-lg text-xs font-mono border border-slate-700 transition-all uppercase tracking-wider"
                 >
                     <Download size={12} className="mr-2" /> Download Asset
                 </a>
              </div>
            ) : (
              <div className="w-48 h-48 bg-slate-800 animate-pulse rounded-lg flex items-center justify-center">
                <Loader2 className="animate-spin text-blue-500" />
              </div>
            )}
          </div>

          <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
            <button 
                onClick={() => window.location.reload()}
                className="w-full sm:w-auto px-8 py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-lg font-bold shadow-lg shadow-blue-500/20 transition-all text-sm uppercase tracking-wide flex items-center justify-center"
            >
                <RefreshCw size={16} className="mr-2" /> New Entry
            </button>
          </div>
        </div>
      </Layout>
    );
