        <nav className="flex items-center justify-between pt-8 border-t border-slate-800/50">
          <button
            onClick={prevStep}
            disabled={currentStep === 1 || isSubmitting}
            className={`flex items-center px-6 py-3 rounded-lg font-medium transition-all text-sm
              ${currentStep === 1 
                ? 'text-slate-600 cursor-not-allowed' 
                : 'text-slate-400 hover:text-white hover:bg-slate-800'
              }`}
          >
            <ArrowLeft size={16} className="mr-2" /> Back
          </button>

          {currentStep === STEPS.length ? (
            <button
              onClick={handleSubmit}
              disabled={isSubmitting || !formData.signatures.agreedToTerms}
              className="flex items-center px-8 py-3 bg-gradient-to-r from-blue-600 to-blue-500 text-white rounded-lg hover:shadow-[0_0_20px_rgba(37,99,235,0.4)] transition-all disabled:opacity-50 disabled:shadow-none font-bold tracking-wide text-sm group"
            >
              {isSubmitting ? (
                <>
                  <Loader2 size={18} className="mr-2 animate-spin" /> UPLINKING...
                </>
              ) : (
                <>
                  EXECUTE BOND <Send size={16} className="ml-2 group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform" />
                </>
              )}
            </button>
          ) : (
            <button
              onClick={nextStep}
              className="flex items-center px-8 py-3 bg-slate-100 text-slate-900 rounded-lg hover:bg-white hover:shadow-lg hover:shadow-white/10 transition-all font-bold tracking-wide text-sm group"
            >
              NEXT STEP <ArrowRight size={16} className="ml-2 group-hover:translate-x-1 transition-transform" />
            </button>
          )}
        </nav>
      </div>
    </Layout>
  );
};

