      </Layout>
    );
  }

  if (isSuccess) {
    return (
      <Layout theme={theme} setTheme={setTheme} onAdminClick={() => setView('admin')}>
        <div className="max-w-xl mx-auto mt-8 glass-panel rounded-2xl p-8 md:p-12 text-center animate-scale-in relative overflow-hidden">
          {/* Accent Top Bar */}
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-blue-500 via-purple-500 to-blue-500"></div>

          <div className="w-20 h-20 bg-green-500/10 rounded-full flex items-center justify-center mx-auto mb-6 border border-green-500/20 shadow-[0_0_30px_rgba(74,222,128,0.2)]">
            <CheckCircle size={40} className="text-green-400" strokeWidth={2.5} />
          </div>

          <h2 className="text-3xl font-bold text-white mb-2 tracking-tight">Bond Executed</h2>
          <p className="text-slate-400 mb-8 max-w-sm mx-auto">
            Agreement for <span className="text-slate-200 font-semibold">{formData.scholar.fullName}</span> transmitted to registrar.
          </p>

          {/* QR Section */}
          <div className="bg-slate-900/50 p-6 rounded-xl border border-slate-700/50 mb-8 inline-block relative group">
            <div className="absolute -inset-1 bg-gradient-to-r from-blue-500 to-purple-600 rounded-xl opacity-20 group-hover:opacity-40 transition duration-500 blur"></div>
            <div className="relative">
              {qrCodeUrl ? (
                <div className="space-y-4">
                  <div className="bg-white p-2 rounded-lg">
                     <img src={qrCodeUrl} alt="QR Code" className="w-48 h-48 mix-blend-normal mx-auto" />
                  </div>
                   <div className="flex gap-2">
                     <a 
                         href={qrCodeUrl} 
                         download={`sentinel-access-qr-${formData.scholar.idNumber}.png`}
                         className="flex-1 flex items-center justify-center px-4 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg text-xs font-bold shadow-lg shadow-blue-500/20 transition-all uppercase tracking-wider"
                     >
                         <Download size={14} className="mr-2" /> Download
                     </a>
                     <button
                        onClick={copyLink}
                        className="px-3 py-2 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-lg border border-slate-700 transition-all"
                        title="Copy Link"
                     >
                       <Copy size={14} />
                     </button>
                   </div>
                </div>
              ) : (
                <div className="w-48 h-48 bg-slate-800 animate-pulse rounded-lg flex items-center justify-center">
                  <Loader2 className="animate-spin text-blue-500" />
                </div>
              )}
            </div>
          </div>

          <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
            <button 
                onClick={() => window.location.reload()}
                className="w-full sm:w-auto px-8 py-3 bg-slate-800 hover:bg-slate-700 text-slate-300 border border-slate-700 rounded-lg font-bold transition-all text-sm uppercase tracking-wide flex items-center justify-center"
            >
                <RefreshCw size={16} className="mr-2" /> New Entry
            </button>
          </div>
        </div>
      </Layout>
    );
  }

  return (
    <Layout theme={theme} setTheme={setTheme} onAdminClick={() => setView('admin')}>
      {/* Toast Container - Fixed Position */}
      <div className="fixed top-24 right-4 z-[9999] flex flex-col items-end pointer-events-none w-full max-w-sm px-4">
        {toasts.map(toast => (
          <div key={toast.id} className="pointer-events-auto w-full">
            <Toast toast={toast} onClose={removeToast} />
          </div>
        ))}
      </div>

      <div className="max-w-4xl mx-auto">
        <StepIndicator currentStep={currentStep} totalSteps={STEPS.length} steps={STEPS} />

        <div className="mt-8 mb-12 min-h-[400px]">
          {currentStep === 1 && <Step1Scholar data={formData} updateData={updateFormData} />}
          {currentStep === 2 && <Step2Program data={formData} updateData={updateFormData} />}
          {currentStep === 3 && <Step3GuarantorWitness data={formData} updateData={updateFormData} />}
          {currentStep === 4 && (
            <div className="space-y-6 animate-in fade-in slide-up">
              <Step4Review data={formData} updateData={updateFormData} />

              {/* AI Insight Card - Glassmorphic */}
              <div className="glass-panel p-6 rounded-xl relative overflow-hidden group">
                {isReviewing && (
                  <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm z-10 flex flex-col items-center justify-center">
                    <BrainCircuit size={48} className="text-blue-500 animate-pulse mb-3" />
                    <p className="text-sm font-mono text-blue-300 animate-pulse">ANALYZING DATA PATTERNS...</p>
                  </div>
                )}

                <div className="flex items-center justify-between mb-4">
                  <div className="flex items-center text-blue-100 font-bold text-lg">
                    <Sparkles className="mr-3 text-purple-400" size={20} /> 
                    <span className="gradient-text">AI AUDIT SYSTEM</span>
                  </div>
                  {!aiReview && !isReviewing && (
                    <button 
                      onClick={handleAiReview}
                      className="px-4 py-2 bg-slate-800 hover:bg-slate-700 text-blue-400 border border-slate-700 rounded-lg transition-all text-xs font-mono uppercase tracking-wider"
                    >
                      Run Diagnostics
                    </button>
                  )}
                </div>

                {aiReview ? (
                  <div className="space-y-4 animate-in fade-in">
                    <div className="flex items-center justify-between">
                      <span className="text-xs font-mono text-slate-400 uppercase">Integrity Score</span>
                      <span className={`text-xl font-mono font-bold ${aiReview.score >= 80 ? 'text-green-400' : 'text-yellow-400'}`}>{aiReview.score}/100</span>
                    </div>
                    <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
                      <div className="h-full bg-gradient-to-r from-blue-500 to-purple-500 transition-all duration-1000" style={{ width: `${aiReview.score}%` }}></div>
                    </div>
                    <div className="p-4 bg-slate-800/50 rounded-lg border border-slate-700/50">
                      <p className="text-slate-300 text-sm italic">"{aiReview.feedback}"</p>
                    </div>
                    <button onClick={() => setAiReview(null)} className="text-xs text-slate-500 hover:text-blue-400 font-mono uppercase transition-colors">Reset Analysis</button>
                  </div>
                ) : (
                  <p className="text-slate-400 text-sm">
                    Activate Gemini-3 to perform a tone analysis and completeness check before final execution.
                  </p>
                )}
              </div>
            </div>
          )}
        </div>

        {/* Navigation Bar */}
        <nav className="flex items-center justify-between pt-8 border-t border-slate-800/50">
          <button
            onClick={prevStep}
            disabled={currentStep === 1 || isSubmitting}
            className={`flex items-center px-6 py-3 rounded-lg font-medium transition-all text-sm
              ${currentStep === 1 
                ? 'text-slate-600 cursor-not-allowed' 
                : 'text-slate-400 hover:text-white hover:bg-slate-800'
              }`}
          >
            <ArrowLeft size={16} className="mr-2" /> Back
          </button>

          {currentStep === STEPS.length ? (
            <button
              onClick={handleSubmit}
              disabled={isSubmitting || !formData.signatures.agreedToTerms}
              className="flex items-center px-8 py-3 bg-gradient-to-r from-blue-600 to-blue-500 text-white rounded-lg hover:shadow-[0_0_20px_rgba(37,99,235,0.4)] transition-all disabled:opacity-50 disabled:shadow-none font-bold tracking-wide text-sm group"
            >
              {isSubmitting ? (
                <>
                  <Loader2 size={18} className="mr-2 animate-spin" /> UPLINKING...
                </>
              ) : (
                <>
                  EXECUTE BOND <Send size={16} className="ml-2 group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform" />
                </>
              )}
            </button>
          ) : (
            <button
              onClick={nextStep}
              className="flex items-center px-8 py-3 bg-slate-100 text-slate-900 rounded-lg hover:bg-white hover:shadow-lg hover:shadow-white/10 transition-all font-bold tracking-wide text-sm group"
            >
              NEXT STEP <ArrowRight size={16} className="ml-2 group-hover:translate-x-1 transition-transform" />
            </button>
          )}
        </nav>
      </div>
    </Layout>
  );
};

export default App;

payload.text:
# Scholarship Bond Portal - 6R Methodology UI/UX Enhancement Directives

## Executive Summary
Analysis of Techbridge Oyibi Campus Scholarship Bond Portal applying the 6R methodology (Reduce, Reuse, Recycle, Rethink, Refine, Reimagine) with Hollywood Dashboard aesthetics and Magazine Cover editorial principles.

---

## 1. REDUCE - Eliminate Cognitive Overload

### Authentication Screen (Image 1)

**DIRECTIVE 1.1: Streamline Authentication Flow**
```typescript
// Remove redundant security messaging
- Remove "SECURE DIGITAL HANDSHAKE PROTOCOL" badge (creates anxiety, not trust)
- Consolidate "AUTHORIZED PERSONNEL AUTHENTICATION" into simpler "Login"
- Remove shield icon redundancy (already implied by "Portal Access")

// Simplified Implementation
interface AuthScreen {
  title: "Welcome Back" | "Portal Login"
  subtitle: "Techbridge Scholarship Bond"
  fields: ["Full Name", "Access Code"]
  cta: "Continue"
}
```

**DIRECTIVE 1.2: Reduce Visual Weight**
```css
/* Current: Heavy brown card on light background creates tunnel vision */
.auth-card {
  /* REMOVE: Excessive padding, dark overlay */
  /* ADD: Light, breathable design */
  background: linear-gradient(135deg, #FFFFFF 0%, #FFF8F0 100%);
  border: 2px solid rgba(212, 175, 55, 0.2);
  box-shadow: 0 8px 32px rgba(212, 175, 55, 0.12);
  padding: 48px 40px; /* Reduced from implied ~60px */
}
```

### Form Screen (Image 2)

**DIRECTIVE 1.3: Progressive Disclosure**
```typescript
// Don't show all 4 steps immediately - creates overwhelm
// Show current step prominently, dim future steps

interface StepIndicator {
  currentStep: {
    size: "large",
    opacity: 1,
    label: "visible"
  },
  futureSteps: {
    size: "small",
    opacity: 0.3,
    label: "hidden-until-hover"
  }
}
```

**DIRECTIVE 1.4: Field Reduction Strategy**
```typescript
// Split dense form into micro-interactions
// Current: 6+ fields visible = cognitive overload

// PHASE 1: Core Identity (Current screen)
fields: [
  "Full Name",
  "ID Number"
]

// PHASE 2: Personal Details (Next screen with animation transition)
fields: [
  "Parent/Guardian Name",
  "Residential Address",
  "Contact Number",
  "Professional Email"
]

// Auto-save progress between phases
```

---

## 2. REUSE - Leverage Proven Patterns

### DIRECTIVE 2.1: Implement Magazine Cover Hierarchy
```css
/* Apply Vogue/GQ layout principles */

.page-title {
  /* Magazine masthead treatment */
  font-family: 'Playfair Display', serif; /* or 'Bodoni' */
  font-size: 48px;
  font-weight: 700;
  letter-spacing: -0.02em;
  color: #1A1A1A;
  margin-bottom: 8px;
}

.page-subtitle {
  /* Cover line treatment */
  font-family: 'Inter', sans-serif;
  font-size: 14px;
  font-weight: 400;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: #666666;
  margin-bottom: 48px;
}
```

### DIRECTIVE 2.2: Reuse Successful Dashboard Patterns
```typescript
// Hollywood Dashboard = Data visualization + Elegant simplicity
// Reuse Apple Card application flow patterns

interface ProgressIndicator {
  type: "minimal-dots" | "linear-progress";
  style: {
    activeColor: "#D4AF37", // Gold
    inactiveColor: "rgba(212, 175, 55, 0.2)",
    animation: "smooth-fill 0.6s cubic-bezier(0.4, 0, 0.2, 1)"
  }
}

// Replace numbered steps with elegant progress bar
// Show "Step 1 of 4" in small text below
```

---

## 3. RECYCLE - Repurpose Existing Assets

### DIRECTIVE 3.1: Transform Color Palette
```css
/* Current: Heavy browns feel dated */
/* Recycle into sophisticated earth tones */

:root {
  /* Primary - Warm Prestige */
  --gold-primary: #D4AF37;
  --gold-light: #F4E4C1;
  --gold-dark: #B8941F;

  /* Secondary - Techbridge Heritage */
  --burgundy: #6B2C3E; /* From logo */
  --cream: #FFF8F0;
  --navy: #1A1A2E;

  /* Neutrals - Magazine Clean */
  --gray-900: #1A1A1A;
  --gray-100: #F7F7F7;
  --white: #FFFFFF;
}

/* Replace all brown (#5C4033) instances with this palette */
```

### DIRECTIVE 3.2: Recycle Logo Equity
```html
<!-- Current: Logo hidden in top-left corner -->
<!-- Recycle as brand confidence signal -->

<header class="portal-header">
  <div class="brand-lockup">
    <img src="techbridge-crest.svg" class="crest-large" />
    <div class="brand-text">
      <h1 class="institution-name">Techbridge</h1>
      <p class="campus-name">Oyibi Campus</p>
    </div>
  </div>
  <div class="portal-title">
    <span class="portal-label">Scholarship Bond Portal</span>
  </div>
</header>

<style>
.crest-large {
  width: 64px; /* Increased from ~40px */
  height: 64px;
}
</style>
```

---

## 4. RETHINK - Challenge Assumptions

### DIRECTIVE 4.1: Rethink Authentication Security Theater
```typescript
// ASSUMPTION: More security warnings = More trust
// REALITY: Excess warnings create anxiety

// CURRENT: 
// - Shield icon
// - "PORTAL ACCESS"
// - "AUTHORIZED PERSONNEL AUTHENTICATION"  
// - "SECURE DIGITAL HANDSHAKE PROTOCOL"

// RETHINK:
interface SecureAuth {
  visual_cues: {
    ssl_indicator: "https:// in browser only",
    trust_badge: "none", // Rely on institution brand
    lock_icon: "subtle, in input field"
  },
  messaging: {
    primary: "Welcome to your Scholarship Portal",
    security_note: "Your information is encrypted" // small text, footer
  }
}
```

### DIRECTIVE 4.2: Rethink Step Indicator Design
```typescript
// ASSUMPTION: Users need to see all 4 steps upfront
// REALITY: Creates anxiety about process length

// RETHINK: Confidence-building progression
interface NewStepDesign {
  display: "current-step-focus",
  messaging: {
    header: "Scholar Identity", // Not "Step 01"
    progress: "1 of 4 - 2 minutes remaining",
    completion_ring: "circular-progress-around-number"
  },
  psychology: "game-ification" // Each step feels like achievement
}
```

### DIRECTIVE 4.3: Rethink Error States (Image 3)
```typescript
// CURRENT: Generic warning toast
// "Please provide a valid professional email and complete all required fields"

// RETHINK: Contextual, helpful guidance
interface ErrorHandling {
  type: "inline-validation",
  implementation: {
    email_field: {
      on_blur: "check_validity",
      invalid_state: {
        border_color: "#E74C3C",
        helper_text: "Use your work or school email (e.g., name@university.edu)",
        icon: "info-circle" // Not warning triangle
      }
    },
    required_fields: {
      show_progress: "2 of 6 fields complete",
      highlight_next: "gentle-pulse-animation"
    }
  }
}
```

---

## 5. REFINE - Polish to Perfection

### DIRECTIVE 5.1: Typography Refinement
```css
/* Magazine-quality typography system */

/* Hierarchy Scale (Type Scale: 1.250 - Major Third) */
.text-xs { font-size: 12px; line-height: 16px; } /* Metadata */
.text-sm { font-size: 14px; line-height: 20px; } /* Body secondary */
.text-base { font-size: 16px; line-height: 24px; } /* Body primary */
.text-lg { font-size: 20px; line-height: 28px; } /* Subheadings */
.text-xl { font-size: 24px; line-height: 32px; } /* Section titles */
.text-2xl { font-size: 32px; line-height: 40px; } /* Page titles */
.text-3xl { font-size: 40px; line-height: 48px; } /* Hero */

/* Font Pairing */
--font-display: 'Playfair Display', Georgia, serif;
--font-body: 'Inter', -apple-system, sans-serif;
--font-mono: 'JetBrains Mono', monospace; /* For ID numbers */

/* Weight System */
--weight-regular: 400;
--weight-medium: 500;
--weight-semibold: 600;
--weight-bold: 700;
```

### DIRECTIVE 5.2: Input Field Refinement
```css
/* Current: Basic browser inputs */
/* Refine: Premium form controls */

.form-input {
  /* Spacing */
  padding: 16px 20px;
  border-radius: 12px;

  /* Typography */
  font-size: 16px;
  line-height: 24px;
  font-weight: 500;
  color: var(--gray-900);

  /* Borders */
  border: 2px solid var(--gray-100);
  background: var(--white);
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);

  /* Interactive States */
  &:hover {
    border-color: var(--gold-light);
    background: var(--cream);
  }

  &:focus {
    border-color: var(--gold-primary);
    background: var(--white);
    box-shadow: 0 0 0 4px rgba(212, 175, 55, 0.12);
    outline: none;
  }

  &::placeholder {
    color: #A0A0A0;
    font-weight: 400;
  }
}

/* Floating Label Enhancement */
.form-field {
  position: relative;

  label {
    position: absolute;
    top: 16px;
    left: 20px;
    font-size: 16px;
    color: #A0A0A0;
    pointer-events: none;
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  }

  input:focus + label,
  input:not(:placeholder-shown) + label {
    top: -8px;
    left: 16px;
    font-size: 12px;
    font-weight: 600;
    color: var(--gold-primary);
    background: var(--white);
    padding: 0 4px;
  }
}
```

### DIRECTIVE 5.3: Button Refinement
```css
/* Hollywood Dashboard CTA Treatment */

.btn-primary {
  /* Base */
  padding: 16px 32px;
  border-radius: 12px;
  font-size: 16px;
  font-weight: 600;
  letter-spacing: 0.02em;

  /* Gold Gradient */
  background: linear-gradient(135deg, #D4AF37 0%, #F4D03F 100%);
  color: #1A1A1A;
  border: none;

  /* Shadow Depth */
  box-shadow: 
    0 1px 2px rgba(212, 175, 55, 0.2),
    0 4px 12px rgba(212, 175, 55, 0.3);

  /* Interactive */
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  cursor: pointer;

  &:hover {
    transform: translateY(-2px);
    box-shadow: 
      0 4px 8px rgba(212, 175, 55, 0.3),
      0 8px 24px rgba(212, 175, 55, 0.4);
  }

  &:active {
    transform: translateY(0);
  }

  /* Loading State */
  &[data-loading="true"] {
    position: relative;
    color: transparent;

    &::after {
      content: "";
      position: absolute;
      width: 20px;
      height: 20px;
      border: 3px solid rgba(26, 26, 26, 0.2);
      border-top-color: #1A1A1A;
      border-radius: 50%;
      animation: spin 0.8s linear infinite;
    }
  }
}

@keyframes spin {
  to { transform: rotate(360deg); }
}
```

### DIRECTIVE 5.4: Spacing Refinement
```css
/* 8px grid system - Magazine layout precision */

:root {
  --space-1: 4px;   /* Micro */
  --space-2: 8px;   /* Tight */
  --space-3: 12px;  /* Compact */
  --space-4: 16px;  /* Cozy */
  --space-5: 24px;  /* Comfortable */
  --space-6: 32px;  /* Relaxed */
  --space-8: 48px;  /* Spacious */
  --space-10: 64px; /* Luxurious */
  --space-12: 96px; /* Editorial */
}

/* Apply to sections */
.section-spacing {
  margin-bottom: var(--space-10);
}

.field-spacing {
  margin-bottom: var(--space-5);
}
```

---

## 6. REIMAGINE - Envision the Future

### DIRECTIVE 6.1: Animated Authentication Experience
```typescript
// Reimagine login as welcoming experience

interface AnimatedAuth {
  entrance_sequence: {
    step_1: {
      element: "background",
      animation: "subtle-gradient-shift",
      duration: "3s infinite"
    },
    step_2: {
      element: "logo",
      animation: "fade-in-scale",
      delay: "0.2s",
      duration: "0.8s"
    },
    step_3: {
      element: "form-card",
      animation: "slide-up-fade",
      delay: "0.4s",
      duration: "0.6s"
    },
    step_4: {
      element: "form-fields",
      animation: "stagger-fade-in",
      delay: "0.8s",
      stagger_delay: "0.1s"
    }
  }
}

// Implementation
@keyframes subtle-gradient-shift {
  0%, 100% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
}

.auth-background {
  background: linear-gradient(
    135deg,
    #FFF8F0 0%,
    #FFFFFF 25%,
    #FFF8F0 50%,
    #FFFFFF 75%,
    #FFF8F0 100%
  );
  background-size: 200% 200%;
  animation: subtle-gradient-shift 8s ease infinite;
}
```

### DIRECTIVE 6.2: Smart Form Intelligence
```typescript
// Reimagine form as intelligent conversation

interface SmartForm {
  auto_complete: {
    name_field: {
      suggestion_source: "previous_scholars" | "common_names",
      display: "dropdown_with_avatar_placeholders"
    },
    address_field: {
      integration: "google_places_api",
      auto_format: true,
      validate_ghana_addresses: true
    }
  },

  predictive_validation: {
    id_number: {
      format: "GHA-000000000-0",
      auto_format_as_typing: true,
      check_luhn_algorithm: true,
      verify_against_database: "debounced_500ms"
    },
    email: {
      suggest_domain: ["@st.techbridge.edu.gh", "@gmail.com"],
      warn_typos: ["gmial.com", "yahooo.com"]
    }
  },

  contextual_help: {
    trigger: "field_focus",
    display: "slide-in-tooltip",
    examples: {
      id_number: "GHA-123456789-0",
      parent_name: "Full legal name as on birth certificate"
    }
  }
}
```

### DIRECTIVE 6.3: Progress Gamification
```typescript
// Reimagine steps as achievement journey

interface GamifiedProgress {
  completion_states: {
    step_1: {
      icon: "🎓", // Scholar identity
      achievement_title: "Identity Verified",
      celebration: "subtle-confetti-burst",
      sound: "achievement-chime.mp3" // Optional
    },
    step_2: {
      icon: "📋",
      achievement_title: "Bond Details Recorded",
      celebration: "checkmark-scale-animation"
    },
    step_3: {
      icon: "✍️",
      achievement_title: "Witnesses Confirmed",
      celebration: "signature-draw-animation"
    },
    step_4: {
      icon: "🎉",
      achievement_title: "Agreement Complete!",
      celebration: "full-confetti-celebration",
      next_action: "download_certificate_button"
    }
  },

  visual_feedback: {
    progress_ring: "circular-fill-animation",
    percentage_display: "counting-animation",
    estimated_time: "dynamic-countdown"
  }
}

// Implementation
.achievement-celebration {
  animation: scale-bounce 0.6s cubic-bezier(0.68, -0.55, 0.265, 1.55);
}

@keyframes scale-bounce {
  0% { transform: scale(0); }
  50% { transform: scale(1.1); }
  100% { transform: scale(1); }
}
```

### DIRECTIVE 6.4: Mobile-First Reimagination
```typescript
// Reimagine for thumb-zone optimization

interface MobileOptimization {
  touch_targets: {
    minimum_size: "44px × 44px", // Apple HIG standard
    spacing_between: "8px minimum",
    primary_actions: "bottom_60px" // Thumb reach zone
  },

  input_optimization: {
    show_keyboard_appropriate_type: {
      email: "type='email'",
      phone: "type='tel'",
      id_number: "inputmode='numeric'"
    },
    autofocus: "disabled_on_mobile", // Prevents keyboard jump
    input_font_size: "16px" // Prevents iOS zoom
  },

  gesture_support: {
    swipe_next_step: "enabled",
    pull_to_refresh: "disabled", // Prevents accidental refresh
    pinch_zoom: "disabled_on_form" // Form should be responsive
  }
}
