import React, { ReactNode, useState, useEffect } from 'react';
import { ThemeSwitcher, Theme } from './ui/ThemeSwitcher';
import { Tooltip } from './ui/Tooltip';
import { Share2, Download, ShieldCheck } from 'lucide-react';

interface Props {
  children: ReactNode;
  theme: Theme;
  setTheme: (theme: Theme) => void;
  onAdminClick: () => void;
}

export const Layout: React.FC<Props> = ({ children, theme, setTheme, onAdminClick }) => {
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [isInstallable, setIsInstallable] = useState(false);
  const [canShare, setCanShare] = useState(false);

  useEffect(() => {
    if (navigator.share) {
      setCanShare(true);
    }

    const handler = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
      setIsInstallable(true);
    };

    window.addEventListener('beforeinstallprompt', handler);

    if (window.matchMedia('(display-mode: standalone)').matches) {
      setIsInstallable(false);
    }

    return () => {
      window.removeEventListener('beforeinstallprompt', handler);
    };
  }, []);

  const handleInstallClick = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    if (outcome === 'accepted') {
      setIsInstallable(false);
    }
    setDeferredPrompt(null);
  };

  const handleShare = async () => {
    try {
      await navigator.share({
        title: 'Techbridge Portal',
        text: 'Scholarship Bond Agreement Portal',
        url: window.location.href,
      });
    } catch (err) {
      console.log('Share failed:', err);
    }
  };

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-500 ${theme === 'high-contrast' ? 'high-contrast' : ''} ${theme === 'dark' ? 'dark' : ''}`}>

      {/* Magazine Style Header */}
      <header className="sticky top-0 z-50 bg-white/90 dark:bg-navy/90 backdrop-blur-md border-b border-gold-light/30 transition-all shadow-sm">
        <div className="max-w-7xl mx-auto px-6 py-4 flex items-center justify-between">

          {/* Brand Lockup - RECYCLED Equity */}
          <div className="flex items-center space-x-4">
             <div className="relative group">
                <img 
                  src="https://techbridge.edu.gh/static/TUC_LOGO_1.png" 
                  alt="Techbridge Crest" 
                  className="w-16 h-16 object-contain filter drop-shadow-md group-hover:scale-105 transition-transform duration-500"
                />
             </div>
             <div className="flex flex-col">
                <h1 className="text-2xl font-serif font-bold tracking-tight text-navy dark:text-white leading-none">
                  Techbridge
                </h1>
                <p className="text-xs font-sans font-medium text-gold-600 dark:text-gold-400 uppercase tracking-widest mt-1">
                  Oyibi Campus
                </p>
             </div>
          </div>

          {/* Central Title - Hidden on small mobile */}
          <div className="hidden md:flex flex-col items-center justify-center absolute left-1/2 transform -translate-x-1/2">
             <span className="font-serif text-lg text-gray-800 dark:text-gray-200 tracking-wide">
               Scholarship Bond Portal
             </span>
          </div>

          {/* Actions */}
          <div className="flex items-center space-x-2">
             {canShare && (
               <Tooltip content="Share Portal">
                 <button 
                   onClick={handleShare}
                   className="p-2 text-gray-400 hover:text-gold-600 transition-colors"
                 >
                   <Share2 size={20} />
                 </button>
               </Tooltip>
             )}

             {isInstallable && (
               <Tooltip content="Install App">
                 <button 
                   onClick={handleInstallClick}
                   className="flex items-center px-4 py-2 bg-cream text-gold-900 border border-gold-primary/20 rounded-lg text-xs font-bold hover:bg-gold-50 transition-all uppercase tracking-wider mr-2"
                 >
                   <Download size={14} className="mr-2" /> 
                   Install
                 </button>
               </Tooltip>
             )}

             <div className="h-6 w-px bg-gray-200 dark:bg-gray-700 mx-2"></div>
             <ThemeSwitcher currentTheme={theme} setTheme={setTheme} />
          </div>
        </div>
      </header>

      {/* Main Content Area with Editorial Spacing */}
      <main className="flex-grow container max-w-5xl mx-auto px-4 py-12 relative z-10 animate-fade-in">
        {children}
      </main>

      {/* Minimalist Footer */}
      <footer className="mt-auto border-t border-gold-primary/10 bg-white/50 dark:bg-navy/50 py-12">
        <div className="max-w-5xl mx-auto px-6 flex flex-col md:flex-row justify-between items-center text-gray-500 text-sm">
          <div className="flex flex-col items-center md:items-start space-y-2">
             <p className="font-serif text-gray-900 dark:text-gray-300">© {new Date().getFullYear()} Techbridge University College</p>
             <div className="flex items-center text-xs space-x-4">
                <span className="text-green-600 dark:text-green-400 flex items-center gap-1">
                  <span className="w-1.5 h-1.5 bg-green-500 rounded-full"></span> 
                  System Operational
                </span>
                <span>Encrypted Connection</span>
             </div>
          </div>

          <div className="mt-8 md:mt-0 flex flex-col items-center md:items-end space-y-3">
             <button 
               onClick={onAdminClick}
               className="text-xs font-medium text-gray-400 hover:text-gold-600 transition-colors flex items-center gap-2 group"
             >
               <ShieldCheck size={12} className="group-hover:text-gold-500" />
               Authorized Access
             </button>
          </div>
        </div>
      </footer>
    </div>
  );
};

import React, { useId } from 'react';
import { IMaskInput } from 'react-imask';
import { AlertCircle, Check } from 'lucide-react';

interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  label: string;
  error?: string;
  mask?: string;
  helperText?: string;
}

export const Input: React.FC<InputProps> = ({ 
  label, 
  error, 
  className, 
  id, 
  mask,
  onChange,
  value,
  helperText,
  ...props 
}) => {
  const generatedId = useId();
  const inputId = id || generatedId;
  const hasValue = value && String(value).length > 0;

  // Hollywood Dashboard Input Styles
  const baseClasses = `w-full px-5 py-4 rounded-xl border-2 transition-all outline-none font-medium text-base
    bg-white dark:bg-navy-800 text-gray-900 dark:text-white
    placeholder-transparent
    hover:bg-cream dark:hover:bg-navy-900
    disabled:opacity-50 disabled:cursor-not-allowed
    ${error 
        ? 'border-red-300 focus:border-red-500 focus:ring-4 focus:ring-red-500/10' 
        : 'border-gray-100 dark:border-navy-900 focus:border-gold-primary focus:ring-4 focus:ring-gold-primary/10 hover:border-gold-light'
    } ${className}`;

  return (
    <div className="w-full relative mb-6 group">
      <div className="relative">
        {mask ? (
          <IMaskInput
            mask={mask}
            unmask={false}
            id={inputId}
            className={baseClasses}
            value={value as string}
            placeholder={label} // Placeholder required for floating label trick
            onAccept={(val, mask) => {
              if (onChange) {
                const event = {
                  target: { value: val, name: props.name },
                  currentTarget: { value: val, name: props.name }
                } as any;
                onChange(event);
              }
            }}
            aria-invalid={!!error}
            aria-describedby={error ? `${inputId}-error` : undefined}
            {...(props as any)}
          />
        ) : (
          <input
            id={inputId}
            aria-invalid={!!error}
            aria-describedby={error ? `${inputId}-error` : undefined}
            className={baseClasses}
            value={value}
            onChange={onChange}
            placeholder={label} // Placeholder required for floating label trick
            {...props}
          />
        )}

        {/* Floating Label */}
        <label 
          htmlFor={inputId} 
          className={`absolute left-5 transition-all duration-300 pointer-events-none px-1
            ${hasValue || props.placeholder 
               ? '-top-2.5 text-xs font-semibold text-gold-600 bg-white dark:bg-navy-800' 
               : 'top-4 text-gray-400 text-base'
            }
            peer-placeholder-shown:text-base peer-placeholder-shown:text-gray-400 peer-placeholder-shown:top-4
            peer-focus:-top-2.5 peer-focus:text-xs peer-focus:text-gold-600 peer-focus:bg-white dark:peer-focus:bg-navy-800
            `}
        >
          {label}
        </label>

        {/* Validation Icon */}
        <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none">
            {error ? (
                <AlertCircle className="text-red-500 animate-pulse" size={20} />
            ) : hasValue && !error ? (
                <Check className="text-green-500 opacity-50" size={20} />
            ) : null}
        </div>
      </div>

      {/* Helper / Error Text */}
      <div className="flex justify-between mt-2 px-1">
        {error ? (
          <p id={`${inputId}-error`} role="alert" className="text-xs font-medium text-red-500 flex items-center animate-fade-in">
             {error}
          </p>
        ) : helperText ? (
          <p className="text-xs text-gray-400 font-medium">{helperText}</p>
        ) : null}
      </div>
    </div>
  );
};

