import React, { useEffect } from 'react';
import { CheckCircle, AlertTriangle, Info, X, AlertCircle } from 'lucide-react';

export type ToastType = 'success' | 'error' | 'warning' | 'info';

export interface ToastMessage {
  id: string;
  type: ToastType;
  title: string;
  message: string;
}

interface ToastProps {
  toast: ToastMessage;
  onClose: (id: string) => void;
}

export const Toast: React.FC<ToastProps> = ({ toast, onClose }) => {
  useEffect(() => {
    const timer = setTimeout(() => {
      onClose(toast.id);
    }, 6000);
    return () => clearTimeout(timer);
  }, [toast.id, onClose]);

  const config = {
    success: { icon: CheckCircle, color: 'text-green-700', border: 'border-green-600', bg: 'bg-green-50' },
    error: { icon: AlertCircle, color: 'text-tuc-red', border: 'border-tuc-red', bg: 'bg-red-50' },
    warning: { icon: AlertTriangle, color: 'text-amber-600', border: 'border-amber-500', bg: 'bg-amber-50' },
    info: { icon: Info, color: 'text-tuc-blue', border: 'border-tuc-blue', bg: 'bg-slate-50' },
  };

  const style = config[toast.type];
  const Icon = style.icon;

  return (
    <div 
      role="alert"
      className={`relative flex items-start p-5 mb-3 w-full rounded-lg border-l-4 shadow-editorial animate-slide-in-right overflow-hidden bg-white dark:bg-slate-800
      ${style.border}`}
    >
      <div className={`flex-shrink-0 mr-4 mt-0.5 ${style.color}`}>
        <Icon size={22} />
      </div>
      <div className="flex-1 mr-6">
        <h4 className="text-sm font-bold text-tuc-blue dark:text-white tracking-wide mb-1 font-serif">{toast.title}</h4>
        <p className="text-sm text-slate-600 dark:text-slate-300 leading-relaxed font-sans">{toast.message}</p>
      </div>
      <button 
        onClick={() => onClose(toast.id)}
        className="absolute top-3 right-3 p-1 text-slate-400 hover:text-tuc-blue transition-colors rounded-full"
        aria-label="Close notification"
      >
        <X size={16} />
      </button>
    </div>
  );
};

import React, { ReactNode, useState, useEffect } from 'react';
import { ThemeSwitcher, Theme } from './ui/ThemeSwitcher';
import { Tooltip } from './ui/Tooltip';
import { Share2, Download, ShieldCheck } from 'lucide-react';

interface Props {
  children: ReactNode;
  theme: Theme;
  setTheme: (theme: Theme) => void;
  onAdminClick: () => void;
}

export const Layout: React.FC<Props> = ({ children, theme, setTheme, onAdminClick }) => {
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [isInstallable, setIsInstallable] = useState(false);
  const [canShare, setCanShare] = useState(false);

  useEffect(() => {
    if (navigator.share) {
      setCanShare(true);
    }

    const handler = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
      setIsInstallable(true);
    };

    window.addEventListener('beforeinstallprompt', handler);

    if (window.matchMedia('(display-mode: standalone)').matches) {
      setIsInstallable(false);
    }

    return () => {
      window.removeEventListener('beforeinstallprompt', handler);
    };
  }, []);

  const handleInstallClick = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    if (outcome === 'accepted') {
      setIsInstallable(false);
    }
    setDeferredPrompt(null);
  };

  const handleShare = async () => {
    try {
      await navigator.share({
        title: 'Techbridge Portal',
        text: 'Scholarship Bond Agreement Portal',
        url: window.location.href,
      });
    } catch (err) {
      console.log('Share failed:', err);
    }
  };

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-500 ${theme === 'high-contrast' ? 'high-contrast' : ''} ${theme === 'dark' ? 'dark' : ''}`}>

      {/* Brand Header */}
      <header className="sticky top-0 z-50 bg-white/95 dark:bg-tuc-blue/95 backdrop-blur-md border-b-2 border-tuc-red transition-all shadow-sm">
        <div className="max-w-7xl mx-auto px-6 py-3 flex items-center justify-between">

          {/* Brand Lockup */}
          <div className="flex items-center space-x-4">
             <div className="relative group">
                <img 
                  src="https://techbridge.edu.gh/static/TUC_LOGO_1.png" 
                  alt="Techbridge Crest" 
                  className="w-14 h-14 object-contain filter drop-shadow-sm group-hover:scale-105 transition-transform duration-500"
                />
             </div>
             <div className="flex flex-col">
                <h1 className="text-2xl font-serif font-bold tracking-tight text-tuc-blue dark:text-white leading-none">
                  Techbridge
                </h1>
                <p className="text-xs font-sans font-bold text-tuc-red dark:text-tuc-red-300 uppercase tracking-widest mt-1">
                  University College
                </p>
             </div>
          </div>

          {/* Central Title - Hidden on small mobile */}
          <div className="hidden md:flex flex-col items-center justify-center absolute left-1/2 transform -translate-x-1/2">
             <span className="font-serif text-lg text-slate-600 dark:text-slate-300 tracking-wide">
               Scholarship Bond Portal
             </span>
          </div>

          {/* Actions */}
          <div className="flex items-center space-x-2">
             {canShare && (
               <Tooltip content="Share Portal">
                 <button 
                   onClick={handleShare}
                   className="p-2 text-slate-400 hover:text-tuc-blue dark:hover:text-white transition-colors hc-text"
                 >
                   <Share2 size={20} />
                 </button>
               </Tooltip>
             )}

             {isInstallable && (
               <Tooltip content="Install App">
                 <button 
                   onClick={handleInstallClick}
                   className="flex items-center px-4 py-2 bg-tuc-blue/5 text-tuc-blue dark:bg-white/10 dark:text-white border border-tuc-blue/10 rounded-lg text-xs font-bold hover:bg-tuc-blue/10 transition-all uppercase tracking-wider mr-2 hc-bg hc-border hc-text-accent hc-focus"
                 >
                   <Download size={14} className="mr-2" /> 
                   Install
                 </button>
               </Tooltip>
             )}

             <div className="h-6 w-px bg-slate-200 dark:bg-slate-600 mx-2 hc-border"></div>
             <ThemeSwitcher currentTheme={theme} setTheme={setTheme} />
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-grow container max-w-5xl mx-auto px-4 py-12 relative z-10 animate-fade-in">
