import React, { useId } from 'react';
import { IMaskInput } from 'react-imask';
import { AlertCircle, Check } from 'lucide-react';

interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  label: string;
  error?: string;
  mask?: string;
  helperText?: string;
}

export const Input: React.FC<InputProps> = ({ 
  label, 
  error, 
  className, 
  id, 
  mask,
  onChange,
  value,
  helperText,
  ...props 
}) => {
  const generatedId = useId();
  const inputId = id || generatedId;
  const hasValue = value && String(value).length > 0;

  // Corporate Input Styles
  const baseClasses = `w-full px-5 py-4 rounded-lg border-2 transition-all outline-none font-medium text-base
    bg-white dark:bg-slate-800 text-slate-900 dark:text-white
    placeholder-transparent
    hover:bg-slate-50 dark:hover:bg-slate-800
    disabled:opacity-50 disabled:cursor-not-allowed
    ${error 
        ? 'border-tuc-red-300 focus:border-tuc-red-500 focus:ring-4 focus:ring-tuc-red-500/10 hc-border hc-text-accent hc-focus' 
        : 'border-slate-200 dark:border-slate-700 focus:border-tuc-blue focus:ring-4 focus:ring-tuc-blue/10 hover:border-tuc-blue-300 hc-border hc-text hc-focus'
    } ${className}`;

  return (
    <div className="w-full relative mb-6 group">
      <div className="relative">
        {mask ? (
          <IMaskInput
            mask={mask}
            unmask={false}
            id={inputId}
            className={baseClasses}
            value={value as string}
            placeholder={label} // Placeholder required for floating label trick
            onAccept={(val, mask) => {
              if (onChange) {
                const event = {
                  target: { value: val, name: props.name },
                  currentTarget: { value: val, name: props.name }
                } as any;
                onChange(event);
              }
            }}
            aria-invalid={!!error}
            aria-describedby={error ? `${inputId}-error` : undefined}
            {...(props as any)}
          />
        ) : (
          <input
            id={inputId}
            aria-invalid={!!error}
            aria-describedby={error ? `${inputId}-error` : undefined}
            className={baseClasses}
            value={value}
            onChange={onChange}
            placeholder={label} // Placeholder required for floating label trick
            {...props}
          />
        )}

        {/* Floating Label */}
        <label 
          htmlFor={inputId} 
          className={`absolute left-5 transition-all duration-300 pointer-events-none px-1
            ${hasValue || props.placeholder 
               ? '-top-2.5 text-xs font-bold text-tuc-blue dark:text-tuc-blue-300 bg-white dark:bg-slate-800 uppercase tracking-wider hc-text-accent hc-bg' 
               : 'top-4 text-slate-400 text-base hc-text'
            }
            peer-placeholder-shown:text-base peer-placeholder-shown:text-slate-400 peer-placeholder-shown:top-4 hc-text
            peer-focus:-top-2.5 peer-focus:text-xs peer-focus:text-tuc-blue dark:peer-focus:text-tuc-blue-300 peer-focus:bg-white dark:peer-focus:bg-slate-800 peer-focus:uppercase peer-focus:tracking-wider hc-text-accent hc-bg
            `}
        >
          {label}
        </label>

        {/* Validation Icon */}
        <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none">
            {error ? (
                <AlertCircle className="text-tuc-red animate-pulse hc-text-accent" size={20} />
            ) : hasValue && !error ? (
                <Check className="text-green-500 opacity-50 hc-text" size={20} />
            ) : null}
        </div>
      </div>

      {/* Helper / Error Text */}
      <div className="flex justify-between mt-2 px-1">
        {error ? (
          <p id={`${inputId}-error`} role="alert" className="text-xs font-bold text-tuc-red flex items-center animate-fade-in hc-text-accent">
             {error}
          </p>
        ) : helperText ? (
          <p className="text-xs text-slate-400 font-medium hc-text">{helperText}</p>
        ) : null}
      </div>
    </div>
  );
};

