              <dd className="font-semibold text-slate-900 dark:text-white text-right hc-text">{data.scholar.title} {data.scholar.fullName}</dd>
            </div>
            <div className="flex justify-between py-2 border-b border-slate-50 dark:border-slate-700/50 hc-border">
