                    <div className="border-2 border-slate-200 dark:border-slate-700 rounded-3xl bg-white touch-none cursor-crosshair overflow-hidden hc-border hc-bg shadow-inner">
                        <canvas
                            ref={canvasRef}
                            width={800}
                            height={300}
                            className="w-full h-64 md:h-80"
                            onMouseDown={startDrawing}
                            onMouseMove={draw}
                            onMouseUp={stopDrawing}
                            onMouseLeave={stopDrawing}
                            onTouchStart={startDrawing}
                            onTouchMove={draw}
                            onTouchEnd={stopDrawing}
                        />
                    </div>
                 </div>
             )}
           </div>
        </div>
      </Section>
    </div>
  );
};

