                    Our embedded AI will analyze the agreement for tone consistency and data completeness before final execution.
                  </p>
                )}
              </div>
            </div>
          )}
        </div>

        {/* Action Bar */}
        <nav className="flex items-center justify-between pt-8 border-t border-slate-200 dark:border-slate-800 hc-border">
          <button
            onClick={prevStep}
            disabled={currentStep === 1 || isSubmitting}
            className={`flex items-center px-6 py-3 rounded-lg font-bold transition-all text-sm
