import React, { useRef, useState, useEffect } from 'react';
import { FormData } from '../../types';
import { Section } from '../ui/Section';
import { Tooltip } from '../ui/Tooltip';
import { FileText, PenTool, Type, MousePointer2, Eraser, Info } from 'lucide-react';
import html2canvas from 'html2canvas';

interface Props {
  data: FormData;
  updateData: (data: Partial<FormData>) => void;
}

export const Step4Review: React.FC<Props> = ({ data, updateData }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const textSignatureRef = useRef<HTMLDivElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);

  useEffect(() => {
    if (!data.signatures.signatureType) {
      updateData({
        signatures: { ...data.signatures, signatureType: 'text' }
      });
    }
  }, []);

  // Auto-generate image from text signature
  useEffect(() => {
    if (data.signatures.signatureType === 'text' && data.signatures.scholarSign?.trim()) {
      const timer = setTimeout(async () => {
        if (textSignatureRef.current) {
          try {
            // Capture the signature visual with transparency
            const canvas = await html2canvas(textSignatureRef.current, {
              backgroundColor: null,
              scale: 2, // Retain high quality
              logging: false,
            });
            const imgData = canvas.toDataURL('image/png');
            handleSignatureChange('signatureImage', imgData);
          } catch (err) {
            console.error("Signature rasterization failed:", err);
          }
        }
      }, 800); // Debounce to avoid lag while typing
      return () => clearTimeout(timer);
    } else if (data.signatures.signatureType === 'text' && !data.signatures.scholarSign?.trim()) {
       handleSignatureChange('signatureImage', '');
    }
  }, [data.signatures.scholarSign, data.signatures.signatureType]);

  const handleSignatureChange = (field: keyof typeof data.signatures, value: any) => {
    updateData({
      signatures: { ...data.signatures, [field]: value },
    });
  };

  const clearCanvas = () => {
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        handleSignatureChange('signatureImage', '');
      }
    }
  };

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    setIsDrawing(true);
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      if (ctx) {
        const rect = canvas.getBoundingClientRect();
        const x = ('touches' in e) ? e.touches[0].clientX - rect.left : (e as React.MouseEvent).nativeEvent.offsetX;
        const y = ('touches' in e) ? e.touches[0].clientY - rect.top : (e as React.MouseEvent).nativeEvent.offsetY;
        ctx.beginPath();
        ctx.moveTo(x, y);
        ctx.lineWidth = 3;
        ctx.lineCap = 'round';
        ctx.strokeStyle = '#0f172a'; // Deep slate (ink color)
      }
    }
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing) return;
    const canvas = canvasRef.current;
    if (canvas) {
      const ctx = canvas.getContext('2d');
      if (ctx) {
        const rect = canvas.getBoundingClientRect();
        const x = ('touches' in e) ? e.touches[0].clientX - rect.left : (e as React.MouseEvent).nativeEvent.offsetX;
        const y = ('touches' in e) ? e.touches[0].clientY - rect.top : (e as React.MouseEvent).nativeEvent.offsetY;
        ctx.lineTo(x, y);
        ctx.stroke();
      }
    }
  };

  const stopDrawing = () => {
    if (isDrawing) {
        setIsDrawing(false);
        const canvas = canvasRef.current;
        if (canvas) {
            handleSignatureChange('signatureImage', canvas.toDataURL());
        }
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="bg-slate-900 text-white p-8 rounded-2xl shadow-xl hc-bg hc-border border border-slate-800 hc-text">
        <h2 className="text-3xl font-black mb-2 flex items-center hc-text tracking-tight">
          <FileText className="mr-3 text-tuc-blue hc-text-accent" size={32} /> Final Review
        </h2>
        <p className="text-slate-400 hc-text text-sm">
          Please verify that all information is accurate. Errors may delay the scholarship disbursement.
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 hc-bg hc-border hc-text">
          <h3 className="font-bold text-slate-800 dark:text-white mb-4 flex items-center text-sm uppercase tracking-wider hc-text">
            <Info size={16} className="mr-2 text-tuc-blue hc-text-accent" /> Scholar Profile
          </h3>
          <dl className="space-y-3 text-sm">
            <div className="flex justify-between py-2 border-b border-slate-50 dark:border-slate-700/50 hc-border">
              <dt className="text-slate-500 dark:text-slate-400 hc-text">Name:</dt>
              <dd className="font-semibold text-slate-900 dark:text-white text-right hc-text">{data.scholar.title} {data.scholar.fullName}</dd>
            </div>
            <div className="flex justify-between py-2 border-b border-slate-50 dark:border-slate-700/50 hc-border">
              <dt className="text-slate-500 dark:text-slate-400 hc-text">ID / Passport:</dt>
              <dd className="font-semibold text-slate-900 dark:text-white text-right hc-text">{data.scholar.idNumber}</dd>
            </div>
            <div className="flex justify-between py-2">
              <dt className="text-slate-500 dark:text-slate-400 hc-text">Guarantor:</dt>
              <dd className="font-semibold text-slate-900 dark:text-white text-right hc-text">{data.guarantor.name}</dd>
            </div>
          </dl>
        </div>

        <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 hc-bg hc-border hc-text">
          <h3 className="font-bold text-slate-800 dark:text-white mb-4 flex items-center text-sm uppercase tracking-wider hc-text">
            <Info size={16} className="mr-2 text-tuc-blue hc-text-accent" /> Bond Obligations
          </h3>
          <dl className="space-y-3 text-sm">
            <div className="flex justify-between py-2 border-b border-slate-50 dark:border-slate-700/50 hc-border">
              <dt className="text-slate-500 dark:text-slate-400 hc-text">Department:</dt>
              <dd className="font-semibold text-slate-900 dark:text-white text-right hc-text">{data.program.department}</dd>
            </div>
            <div className="flex justify-between py-2 border-b border-slate-50 dark:border-slate-700/50 hc-border">
              <dt className="text-slate-500 dark:text-slate-400 hc-text">PhD Research:</dt>
              <dd className="font-semibold text-slate-900 dark:text-white text-right italic hc-text">{data.program.phdSubject || 'Pending Selection'}</dd>
            </div>
            <div className="flex justify-between py-3 px-3 bg-red-50 dark:bg-red-900/10 rounded-xl mt-2 hc-bg hc-border">
              <dt className="text-red-700 dark:text-red-300 font-bold hc-text-accent">Service Bond:</dt>
              <dd className="font-black text-red-800 dark:text-red-200 hc-text-accent">{data.program.serviceYears} Consecutive Years</dd>
            </div>
          </dl>
        </div>
      </div>

      <Section title="E-Signature Verification" description="Legally binding digital signature required for execution.">
        <div className="space-y-8">
           <div className="bg-amber-50 dark:bg-amber-900/10 p-5 rounded-2xl border border-amber-200 dark:border-amber-800/50 hc-border hc-bg">
             <label className="flex items-start space-x-4 cursor-pointer">
               <input 
                 type="checkbox" 
                 className="mt-1.5 w-6 h-6 rounded-lg border-amber-300 text-tuc-blue-600 focus:ring-tuc-blue-500 transition-all hc-border hc-text-accent hc-focus"
                 checked={data.signatures.agreedToTerms}
                 onChange={(e) => handleSignatureChange('agreedToTerms', e.target.checked)}
               />
               <span className="text-sm text-amber-900 dark:text-amber-200 hc-text leading-relaxed">
                 I confirm that the details provided are true and correct. I understand that this digital signature constitutes a legally binding agreement under the <strong>Electronic Communications and Transactions Act</strong>.
               </span>
             </label>
           </div>

           <div className="space-y-6">
             <div className="flex space-x-1 p-1 bg-slate-100 dark:bg-slate-700/50 rounded-xl w-fit hc-bg hc-border">
                <Tooltip content="Sign by typing">
                  <button
                      onClick={() => handleSignatureChange('signatureType', 'text')}
                      className={`flex items-center px-6 py-3 text-sm font-bold rounded-lg transition-all ${
                          data.signatures.signatureType === 'text' 
                          ? 'bg-white dark:bg-slate-600 text-tuc-blue-600 dark:text-tuc-blue-400 shadow-sm hc-bg hc-text-accent' 
                          : 'text-slate-500 hover:text-slate-700 dark:text-slate-400 hc-text'
                      }`}
                  >
                      <Type size={18} className="mr-2" /> Textual
                  </button>
                </Tooltip>
                <Tooltip content="Sign by drawing">
                  <button
                      onClick={() => handleSignatureChange('signatureType', 'draw')}
                      className={`flex items-center px-6 py-3 text-sm font-bold rounded-lg transition-all ${
                          data.signatures.signatureType === 'draw' 
                          ? 'bg-white dark:bg-slate-600 text-tuc-blue-600 dark:text-tuc-blue-400 shadow-sm hc-bg hc-text-accent' 
                          : 'text-slate-500 hover:text-slate-700 dark:text-slate-400 hc-text'
                      }`}
                  >
                      <MousePointer2 size={18} className="mr-2" /> Handwritten
                  </button>
                </Tooltip>
             </div>

             {data.signatures.signatureType === 'text' ? (
                 <div className="animate-in fade-in slide-in-from-top-4">
                    <div className="mb-4">
                      <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2 hc-text">Full Legal Name</label>
                      <input
                          type="text"
                          placeholder="Type your full name exactly as it appears on your ID"
                          className="w-full px-5 py-4 rounded-xl border border-slate-200 dark:border-slate-700 focus:ring-4 focus:ring-tuc-blue-500/10 focus:border-tuc-blue-500 transition-all bg-white dark:bg-slate-800 dark:text-white hc-bg hc-text hc-border text-lg font-medium hc-focus"
                          value={data.signatures.scholarSign}
                          onChange={(e) => handleSignatureChange('scholarSign', e.target.value)}
                      />
                    </div>

                    {/* Visual Preview Container - Styled to look like paper for better capture */}
                    <div className="p-8 md:p-12 border-2 border-dashed border-slate-300 rounded-3xl bg-white relative overflow-hidden hc-bg hc-border flex items-center justify-center shadow-inner">
                        <div className="absolute top-4 left-6 flex items-center text-slate-400 text-[10px] uppercase tracking-[0.2em] font-black hc-text-accent">
                          <PenTool size={14} className="mr-2 text-tuc-blue hc-text-accent" /> Digital Preview
                        </div>

                        {/* The Capture Target - We enforce dark text on white/transparent to simulate real ink */}
                        <div id="text-signature-preview" ref={textSignatureRef} className="flex flex-col items-center justify-center p-4">
                            {data.signatures.scholarSign ? (
                                <div className="text-6xl md:text-8xl font-signature text-slate-900 transform -rotate-2 leading-none px-6 py-4 text-center hc-text-inverted filter drop-shadow-sm min-h-[120px] flex items-center">
                                    {data.signatures.scholarSign}
                                </div>
                            ) : (
                                <div className="text-slate-300 text-4xl font-signature opacity-50 select-none min-h-[120px] flex items-center hc-text-inverted">
                                    Sign Here
                                </div>
                            )}
                            {/* Decorative Line (included in capture) */}
                            <div className="w-64 h-1 bg-slate-900 rounded-full opacity-80 mt-2 hc-bg-inverted"></div>
                        </div>
                    </div>
                 </div>
             ) : (
                 <div className="animate-in fade-in slide-in-from-top-4">
                    <div className="flex justify-between items-center mb-3">
                        <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 hc-text">Electronic Pad</label>
                        <Tooltip content="Wipe signature and restart">
                          <button 
                              onClick={clearCanvas}
                              className="text-xs font-bold flex items-center text-slate-400 hover:text-red-500 transition-colors uppercase tracking-widest hc-text-accent"
                          >
                              <Eraser size={14} className="mr-2" /> Reset
                          </button>
                        </Tooltip>
                    </div>
                    <div className="border-2 border-slate-200 dark:border-slate-700 rounded-3xl bg-white touch-none cursor-crosshair overflow-hidden hc-border hc-bg shadow-inner">
                        <canvas
                            ref={canvasRef}
                            width={800}
                            height={300}
                            className="w-full h-64 md:h-80"
                            onMouseDown={startDrawing}
                            onMouseMove={draw}
                            onMouseUp={stopDrawing}
                            onMouseLeave={stopDrawing}
                            onTouchStart={startDrawing}
                            onTouchMove={draw}
                            onTouchEnd={stopDrawing}
                        />
                    </div>
                 </div>
             )}
           </div>
        </div>
      </Section>
    </div>
  );
};

import { FormData } from '../types';

export interface TestResult {
  id: string;
  timestamp: string;
  status: 'passed' | 'failed';
  screenshot?: string; // Base64
  duration: number;
  log: string[];
}

const TEST_RESULTS_KEY = 'techbridge_test_results';

export const getTestResults = (): TestResult[] => {
  try {
    const data = localStorage.getItem(TEST_RESULTS_KEY);
    return data ? JSON.parse(data) : [];
  } catch (e) {
    return [];
  }
};

export const saveTestResult = (result: TestResult) => {
  const existing = getTestResults();
  const updated = [result, ...existing].slice(0, 10); // Keep last 10
  localStorage.setItem(TEST_RESULTS_KEY, JSON.stringify(updated));
};

